patch:
diff --git a/drivers/acpi/video.c b/drivers/acpi/video.c
index fcbda105616e..c3897fe53cb4 100644
--- a/drivers/acpi/video.c
+++ b/drivers/acpi/video.c
@@ -1407,10 +1407,30 @@ acpi_video_device_bind(struct acpi_video_bus *video,
 		if (device->device_id == (ids->value.int_val & 0xffff)) {
 			ids->bind_info = device;
 			ACPI_DEBUG_PRINT((ACPI_DB_INFO, "device_bind %d\n", i));
+			dev_info(&device->dev->dev, "bound video output device _ADR: 0x%x\n", device->device_id);
 		}
 	}
 }

+static bool acpi_video_device_in_dod(struct acpi_video_device *device)
+{
+	struct acpi_video_bus *video = device->video;
+	int i;
+
+	/* If we have a broken _DOD, no need to test */
+	if (!video->attached_count) {
+		dev_info(&video->device->dev, "broken _DOD\n");
+		return true;
+	}
+
+	for (i = 0; i < video->attached_count; i++) {
+		if (video->attached_array[i].bind_info == device)
+			return true;
+	}
+
+	return false;
+}
+
 /*
  *  Arg:
  *	video	: video bus device
@@ -1468,8 +1488,8 @@ static int acpi_video_device_enumerate(struct acpi_video_bus *video)

 		active_list[count].value.int_val = obj->integer.value;
 		active_list[count].bind_info = NULL;
-		ACPI_DEBUG_PRINT((ACPI_DB_INFO, "dod element[%d] = %d\n", i,
-				  (int)obj->integer.value));
+		dev_info(&video->device->dev, "dod element[%d] = 0x%x\n", i,
+				  (int)obj->integer.value);
 		count++;
 	}

@@ -1850,6 +1870,15 @@ static void acpi_video_dev_register_backlight(struct acpi_video_device *device)
 	static int count;
 	char *name;

+	/*
+	 * Do not create backlight device for video output
+	 * device that is not in the enumerated list.
+	 */
+	if (!acpi_video_device_in_dod(device)) {
+		dev_info(&device->dev->dev, "not in _DOD list, ignore\n");
+		return;
+	}
+
 	result = acpi_video_init_brightness(device);
 	if (result)
 		return;
@@ -1878,6 +1907,8 @@ static void acpi_video_dev_register_backlight(struct acpi_video_device *device)
 	if (IS_ERR(device->backlight))
 		return;

+	dev_info(&device->dev->dev, "created backlight device\n");
+
 	/*
 	 * Save current brightness level in case we have to restore it
 	 * before acpi_video_device_lcd_set_level() is called next time.
